// export default LoginModal;

import React, { useState, useEffect } from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
// import styled from 'styled-components';

const LoginModal = ({ isOpen, onClose, onRegisterClick }) => {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [isVisible, setIsVisible] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [formError, setFormError] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [showForgotPassword, setShowForgotPassword] = useState(false);
    const [forgotEmail, setForgotEmail] = useState('');
    const [forgotLoading, setForgotLoading] = useState(false);
    const [forgotMessage, setForgotMessage] = useState('');
    const [forgotError, setForgotError] = useState('');
    const history = useHistory();

    const API_BASE_URL = process.env.REACT_APP_API_URL;

    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
            requestAnimationFrame(() => {
                setIsVisible(true);
            });
        } else {
            setIsVisible(false);
            document.body.style.overflow = 'auto';
        }
        
        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [isOpen]);

    useEffect(() => {
        const handleEsc = (event) => {
            if (event.keyCode === 27) onClose();
        };
        window.addEventListener('keydown', handleEsc);
        
        return () => {
            window.removeEventListener('keydown', handleEsc);
        };
    }, [onClose]);

    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setForgotError('');
        setForgotMessage('');
        setForgotLoading(true);
    
        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/forgot-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ email: forgotEmail })
            });
    
            const data = await response.json();
    
            if (!response.ok) {
                throw new Error(data.message || 'Failed to send reset email');
            }
    
            setForgotMessage('OTP sent successfully! Redirecting...');
            
            setTimeout(() => {
                history.push('/verify-otp', { 
                    email: forgotEmail 
                });
                onClose();
            }, 1500);
    
        } catch (error) {
            console.error('Forgot password error:', error);
            setForgotError(error.message || 'Service temporarily unavailable. Please contact support.');
        } finally {
            setForgotLoading(false);
        }
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setFormError('');
        setIsLoading(true);
        
        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/login`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    email,
                    password
                })
            });

            const contentType = response.headers.get('content-type');
            if (!contentType || !contentType.includes('application/json')) {
                throw new Error('Server returned non-JSON response. Check if the API endpoint exists.');
            }

            const data = await response.json();
            
            if (!response.ok) {
                throw new Error(data.message || t('login.errors.loginFailed'));
            }
            
            localStorage.setItem('authToken', data.token);
            localStorage.setItem('userRole', data.role || data.user?.role);
            localStorage.setItem('userEmail', data.user?.email || email);
            localStorage.setItem('userName', `${data.user?.firstName || ''} ${data.user?.lastName || ''}`.trim());
            localStorage.setItem('userId', data.user?.id);
            
            onClose();
            history.push('/dashboard');
            
        } catch (error) {
            console.error('Login error:', error);
            
            let errorMessage = t('login.errors.invalidCredentials');
            
            if (error.message.includes('non-JSON response')) {
                errorMessage = 'Server error. Please check if the backend is running properly.';
            } else if (error.message.includes('Failed to fetch')) {
                errorMessage = 'Cannot connect to server. Please check your internet connection.';
            } else if (error.message) {
                errorMessage = error.message;
            }
            
            setFormError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        if (!isOpen) {
            setEmail('');
            setPassword('');
            setFormError('');
            setShowForgotPassword(false);
            setForgotEmail('');
            setForgotError('');
            setForgotMessage('');
        }
    }, [isOpen]);

    return (
        <StyledWrapper className={`login-modal-overlay ${isOpen ? 'active' : ''} ${isVisible ? 'visible' : ''}`} onClick={onClose}>
            <div className="card" onClick={e => e.stopPropagation()}>
                <button className="modal-close-btn" onClick={onClose} aria-label={t('login.closeModal')}>
                    ×
                </button>

                <input 
                    defaultValue={showPassword} 
                    className="blind-check" 
                    type="checkbox" 
                    id="blind-input" 
                    name="blindcheck" 
                    hidden 
                    checked={showPassword}
                    onChange={() => setShowPassword(!showPassword)}
                />

                {!showForgotPassword && (
                    <label htmlFor="blind-input" className="blind_input">
                        <span className="hide">Hide</span>
                        <span className="show">Show</span>
                    </label>
                )}

                <form className="form" onSubmit={showForgotPassword ? handleForgotPassword : handleLogin}>
                    <div className="title">
                        {showForgotPassword ? 'Reset Password' : t('login.header.title') || 'Sign In'}
                    </div>

                    {(formError || forgotError) && (
                        <div className="form-error">
                            <span className="error-icon">⚠</span>
                            <span>{formError || forgotError}</span>
                        </div>
                    )}

                    {forgotMessage && (
                        <div className="form-success">
                            <span className="success-icon">✓</span>
                            <span>{forgotMessage}</span>
                        </div>
                    )}

                    {!showForgotPassword ? (
                        <>
                            <label className="label_input" htmlFor="email-input">
                                {t('login.form.emailPlaceholder') || 'Email'}
                            </label>
                            <input 
                                spellCheck="false" 
                                className="input" 
                                type="email" 
                                name="email" 
                                id="email-input"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                required
                            />

                            <div className="frg_pss">
                                <label className="label_input" htmlFor="password-input">
                                    {t('login.form.passwordPlaceholder') || 'Password'}
                                </label>
                                <a 
                                    href="#"
                                    onClick={(e) => {
                                        e.preventDefault();
                                        setShowForgotPassword(true);
                                    }}
                                >
                                    {t('login.form.forgotPassword') || 'Forgot password?'}
                                </a>
                            </div>
                            <input 
                                spellCheck="false" 
                                className="input" 
                                type="text" 
                                name="password" 
                                id="password-input"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                required
                            />

                            <div className="form-options">
                                <label className="custom-checkbox">
                                    <input
                                        type="checkbox"
                                        checked={rememberMe}
                                        onChange={() => setRememberMe(!rememberMe)}
                                    />
                                    <span className="checkbox-label">
                                        {t('login.form.rememberMe') || 'Remember me'}
                                    </span>
                                </label>
                            </div>

                            <button 
                                className="submit" 
                                type="submit"
                                disabled={isLoading}
                            >
                                {isLoading ? (t('login.form.signingIn') || 'Signing In...') : (t('login.form.signIn') || 'Sign In')}
                            </button>

                            <div className="register-section">
                                <div className="divider-text">
                                    {t('login.register.newToPlatform') || 'New to platform?'}
                                </div>
                                <button
                                    type="button"
                                    className="register-button"
                                    onClick={(e) => {
                                        e.preventDefault();
                                        onRegisterClick();
                                    }}
                                >
                                    {t('login.register.createAccount') || 'Create Account'}
                                </button>
                            </div>
                        </>
                    ) : (
                        <>
                            <label className="label_input" htmlFor="forgot-email-input">Email</label>
                            <input 
                                spellCheck="false" 
                                className="input" 
                                type="email" 
                                name="email" 
                                id="forgot-email-input"
                                value={forgotEmail}
                                onChange={(e) => setForgotEmail(e.target.value)}
                                placeholder="Enter your email address"
                                required
                            />

                            <button 
                                className="submit" 
                                type="submit"
                                disabled={forgotLoading}
                            >
                                {forgotLoading ? 'Sending...' : 'Send Reset Email'}
                            </button>

                            <button
                                type="button"
