                    )}
                </form>

                <label htmlFor="blind-input" className="avatar">
                    <svg xmlns="http://www.w3.org/2000/svg" width={35} height={35} viewBox="0 0 64 64" id="monkey">
                        <ellipse cx="53.7" cy={33} rx="8.3" ry="8.2" fill="#89664c" />
